hl.on("hyprland.start", function()
	hl.exec_cmd("waybar & hyprpaper")
	hl.exec_cmd("hyprpanel")
	hl.exec_cmd("cliphist wipe; wl-paste --watch cliphist store")
	hl.exec_cmd("systemctl --user start opentabletdriver.service --now")
end)
